import { useEffect, useState } from 'react'
import {
  getPlaceTypes,
  getPlaceTypeGroups,
  getPlaceSubTypeGroups,
  getProvisionalPlaceFlowTypes,
  getPlaceNameTypes,
} from './placeTypeService'

const useFetchPlaceTypes = (include, fetchFunc) => {
  const [data, setData] = useState([])
  useEffect(() => {
    let isRunning = true
    if (include) {
      fetchFunc().then((types) => {
        if (isRunning) {
          setData(types)
        }
      })
    }
    return () => {
      isRunning = false
    }
  }, [include, fetchFunc])
  return data
}

export default function usePlaceTypeSuggest({
  includePlaceTypes = true,
  includeTypeGroups = false,
  includePlaceFilterSubGroup = false,
  includePPFTypes = false,
  includeNameTypes = false,
  initialSelectedItem,
  ...extraProps
} = {}) {
  const placeTypes = useFetchPlaceTypes(includePlaceTypes, getPlaceTypes)
  const placeTypeGroups = useFetchPlaceTypes(includeTypeGroups, getPlaceTypeGroups)
  const placeFilterSubGroupTypes = useFetchPlaceTypes(includePlaceFilterSubGroup, getPlaceSubTypeGroups)
  const ppfTypes = useFetchPlaceTypes(includePPFTypes, getProvisionalPlaceFlowTypes)
  const nameTypes = useFetchPlaceTypes(includeNameTypes, getPlaceNameTypes)
  const [inputText, setInputText] = useState(initialSelectedItem?.primaryText || '')

  const apiPlaceTypes = placeTypeGroups
    .concat(placeTypes)
    .concat(placeFilterSubGroupTypes)
    .concat(ppfTypes)
    .concat(nameTypes)
  const validPlaceTypes =
    initialSelectedItem && !apiPlaceTypes.find((t) => t.id === initialSelectedItem.id)
      ? apiPlaceTypes.concat(initialSelectedItem)
      : apiPlaceTypes

  const suggestions = validPlaceTypes
    .filter(
      (placeTypeSuggestion) =>
        !inputText ||
        (placeTypeSuggestion.primaryText &&
          placeTypeSuggestion.primaryText.toLowerCase().includes(inputText.toLowerCase())) ||
        (placeTypeSuggestion.secondaryText &&
          placeTypeSuggestion.secondaryText.toLowerCase().includes(inputText.toLowerCase()))
    )
    .sort((t1, t2) => {
      const p1MatchesText = t1.primaryText.toLowerCase().includes(inputText.toLowerCase())
      const p2MatchesText = t2.primaryText.toLowerCase().includes(inputText.toLowerCase())
      if (p1MatchesText && !p2MatchesText) {
        return -1
      }
      if (p2MatchesText && !p1MatchesText) {
        return 1
      }
      return (t1.primaryText || '').localeCompare(t2.primaryText)
    })

  return { inputText, onInputTextChange: setInputText, suggestions, validPlaceTypes, ...extraProps }
}
