import { i18n } from '@fs/zion-locale'
import axios from '@fs/zion-axios'
import zionDebug from '@fs/zion-debug'

const debug = zionDebug('standards:placesTypeService')

let uniqueId = 0
function getXRequestId() {
  const now = Date.now()
  return `${now}-${++uniqueId}-places-react`
}

function getDefaultHeaders() {
  return {
    'Content-Type': 'application/standards-places-v2+json',
    Accept: 'application/json',
    'X-Request-ID': getXRequestId(),
  }
}

function fetchPlaceTypes() {
  debug(`placeTypeService.fetchPlaceTypes: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws-ui/places/place-types?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    fsUserAgentChainSuffix: 'zion-standards',
  })
}

function fetchTypeGroups() {
  debug(`placeTypeService.fetchTypeGroups: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws-ui/places/type-groups?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    fsUserAgentChainSuffix: 'zion-standards',
  })
}

function fetchBasicTypeGroups() {
  debug(`placeTypeService.fetchTypeGroups: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws-ui/places/type-groups/33?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    fsUserAgentChainSuffix: 'zion-standards',
  })
}

function fetchPlaceNameTypes() {
  debug(`fetchPlaceNameTypes: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws-ui/places/name-types?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    fsUserAgentChainSuffix: 'zion-standards',
  })
}

function mapPublishedTypesToSuggestions(types, suffix) {
  if (!Array.isArray(types)) {
    return types
  }

  return types
    .filter((type) => type.published)
    .map((type) => ({
      primaryText: type.localizedName[0].name,
      secondaryText: type.localizedName[0].desc,
      key: `${type.id}-${suffix}`,
      id: type.id,
      type,
    }))
}

export async function getPlaceTypes() {
  try {
    const resp = await fetchPlaceTypes()
    return mapPublishedTypesToSuggestions(resp.data.types, 'placeType')
  } catch (err) {
    debug(`placeTypeService.getPlaceTypes error: ${err}: `)
    return []
  }
}

export async function getPlaceSubTypeGroups() {
  try {
    const resp = await fetchBasicTypeGroups()
    return mapPublishedTypesToSuggestions(resp.data.placeTypeGroup.subGroups, 'groupType')
  } catch (err) {
    debug(`placeBasicTypeService.getPlaceTypeGroups error: ${err}: `)
    return []
  }
}

export async function getPlaceTypeGroups() {
  try {
    const resp = await fetchTypeGroups()
    return mapPublishedTypesToSuggestions(resp.data.placeTypeGroups, 'groupType')
  } catch (err) {
    debug(`placeTypeService.getPlaceTypeGroups error: ${err}: `)
    return []
  }
}

function fetchProvisionalPlaceFlowTypeGroup() {
  debug(`usePlaceTypes.fetchPlaceSuggestTypeGroup: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws-ui/places/type-groups/61?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    fsUserAgentChainSuffix: 'zion-standards',
  })
}

export async function getProvisionalPlaceFlowTypes() {
  try {
    const resp = await fetchProvisionalPlaceFlowTypeGroup()
    const placeSuggestTypes = mapPublishedTypesToSuggestions(resp.data.placeTypeGroup.placeTypes, 'groupType').map(
      (suggestion) => {
        const secondaryText = suggestion.secondaryText.split('"').join('')
        return { ...suggestion, secondaryText }
      }
    )

    placeSuggestTypes.sort((left, right) => left.primaryText.localeCompare(right, i18n.language))
    return placeSuggestTypes
  } catch {
    return []
  }
}

export async function getPlaceNameTypes() {
  try {
    const resp = await fetchPlaceNameTypes()
    return mapPublishedTypesToSuggestions(resp.data.types, 'nameType')
  } catch {
    return []
  }
}
